function _sendSignal(
    address _app,
    bytes32 _signal,
    bytes32 _value
)
    private
    validSender(_app)
    nonZeroValue(_signal)
    nonZeroValue(_value)
    returns (bytes32 slot_)
{
    slot_ = getSignalSlot(uint64(block.chainid), _app, _signal);
    assembly {
        sstore(slot_, _value)
    }
    emit SignalSent(_app, _signal, slot_, _value);
}
